patch:
diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index d7afe2f426d3..50af8deed2ee 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -2645,6 +2645,52 @@ bool VectorCombine::shrinkType(llvm::Instruction &I) {
         Instruction::Trunc, SmallTy, BigTy,
         TargetTransformInfo::CastContextHint::None, CostKind);

+  // For shift operations, we need to ensure that the shift amount after
+  // truncation will not produce poison. If we're shrinking to a type with
+  // bit width BW, the shift amount must be < BW. For non-constant shift
+  // amounts, we cannot guarantee this safety, so we bail out.
+  if (I.getOpcode() == Instruction::LShr || I.getOpcode() == Instruction::AShr ||
+      I.getOpcode() == Instruction::Shl) {
+    // If the shift amount is not a constant, we cannot prove it's safe
+    if (!isa<Constant>(OtherOperand))
+      return false;
+    
+    // For constant shift amounts, check if they are within bounds
+    Constant *ShiftAmt = cast<Constant>(OtherOperand);
+    unsigned SmallBW = SmallTy->getElementType()->getPrimitiveSizeInBits();
+    
+    // Handle both ConstantVector and ConstantDataVector
+    if (auto *VecShift = dyn_cast<ConstantVector>(ShiftAmt)) {
+      for (unsigned i = 0; i < VecShift->getNumOperands(); ++i) {
+        Constant *Elem = VecShift->getOperand(i);
+        if (auto *CI = dyn_cast<ConstantInt>(Elem)) {
+          if (CI->getValue().uge(SmallBW))
+            return false;
+        } else {
+          // Non-integer constant element, can't prove safety
+          return false;
+        }
+      }
+    } else if (auto *DataVec = dyn_cast<ConstantDataVector>(ShiftAmt)) {
+      // ConstantDataVector stores elements in a packed format
+      for (unsigned i = 0; i < DataVec->getNumElements(); ++i) {
+        if (auto *CI = dyn_cast_or_null<ConstantInt>(DataVec->getElementAsConstant(i))) {
+          if (CI->getValue().uge(SmallBW))
+            return false;
+        } else {
+          // Non-integer constant element, can't prove safety
+          return false;
+        }
+      }
+    } else if (auto *CI = dyn_cast<ConstantInt>(ShiftAmt)) {
+      if (CI->getValue().uge(SmallBW))
+        return false;
+    } else {
+      // Other constant types, can't prove safety
+      return false;
+    }
+  }
+
   // If the cost of shrinking types and leaving the IR is the same, we'll lean
   // towards modifying the IR because shrinking opens opportunities for other
   // shrinking optimisations.

